mapper.select:
SELECT COUNT(*)
FROM xml_file
WHERE deleted = 0 and is_latest = 1

        AND create_time >= #{startTime}


        AND create_time < #{endTime}


        AND issue_date >= #{issueStartTime}


        AND issue_date < #{issueEndTime}


        AND factory_code = #{factoryCode}


        AND xml_template_id = #{vehicleModel}


        AND country = #{country}


        AND upload_result = #{uploadResult}

SELECT COUNT(case when upload_result = 4 then 1 end)
FROM xml_file
WHERE deleted = 0 and is_latest = 1 and update_time is not null

        AND update_time >= #{startTime}


        AND update_time < #{endTime}


        AND issue_date >= #{issueStartTime}


        AND issue_date < #{issueEndTime}


        AND factory_code = #{factoryCode}


        AND xml_template_id = #{vehicleModel}


        AND country = #{country}


        AND upload_result = #{uploadResult}

select count(*)
from vehicle_info
where deleted = 0 and upload_status = 0 and status = 0

        AND create_time >= #{startTime}


        AND create_time < #{endTime}

SELECT COUNT(*)
FROM vehicle_info vi
WHERE vi.deleted = 0 and update_time is not null
    AND vi.validation_result = 2
    AND vi.update_time >= IFNULL(#{startTime},        CONCAT(YEAR(NOW()), '-01-01'))
    AND vi.update_time <  IFNULL(#{endTime},       CONCAT(YEAR(NOW()) + 1, '-01-01'))
    AND vi.issue_date  >= IFNULL(#{issueStartTime},   CONCAT(YEAR(NOW()), '-01-01'))
    AND vi.issue_date  <  IFNULL(#{issueEndTime},  CONCAT(YEAR(NOW()) + 1, '-01-01'))

        AND vi.factory_code = #{factoryCode}


        AND vi.vehicle_model = #{vehicleModel}


        AND vi.country = #{country}


        AND vi.upload_status = #{uploadResult}

SELECT COUNT(case when upload_result = 5 then 1 end)
FROM xml_file
WHERE deleted = 0 and is_latest = 1 and update_time is not null

        AND update_time >= #{startTime}


        AND update_time < #{endTime}


        AND issue_date >= #{issueStartTime}


        AND issue_date < #{issueEndTime}


        AND factory_code = #{factoryCode}


        AND xml_template_id = #{vehicleModel}


        AND country = #{country}


        AND upload_result = #{uploadResult}

SELECT YEAR(case when update_time is null then create_time else update_time end) AS year,


            MONTH(case when update_time is null then create_time else update_time end) AS month,




            DAY(case when update_time is null then create_time else update_time end) AS day,


    COUNT(CASE WHEN validate_result IN (0, 1, 2) THEN 1 END) AS total,
    SUM(CASE WHEN validate_result = 2 THEN 1 ELSE 0 END)  AS fail_number,
    SUM(CASE WHEN validate_result = 1 THEN 1 ELSE 0 END)  AS pass_number
FROM xml_file
WHERE deleted = 0 and is_latest = 1

        AND case when update_time is null then create_time else update_time end >= #{startTime}


        AND case when update_time is null then create_time else update_time end < #{endTime}


        AND issue_date >= #{issueStartTime}


        AND issue_date < #{issueEndTime}


        AND factory_code = #{factoryCode}


        AND xml_template_id = #{vehicleModel}


        AND country = #{country}


        AND upload_result = #{uploadResult}

GROUP BY YEAR(case when update_time is null then create_time else update_time end)


            , MONTH(case when update_time is null then create_time else update_time end)




            , DAY(case when update_time is null then create_time else update_time end)


ORDER BY year ASC


            , month ASC




            , day ASC

SELECT vl.*
FROM vehicle_lifecycle vl
         INNER JOIN (
    SELECT operate, MAX(time) AS max_time
    FROM vehicle_lifecycle
    WHERE vin = #{vin}
      AND time <= #{time}
      AND deleted = 0
    GROUP BY operate
) latest ON vl.operate = latest.operate AND vl.time = latest.max_time
WHERE vl.vin = #{vin}
  AND vl.deleted = 0

SELECT ac.rule_type AS abnormal, COUNT(*)     AS count
FROM abnormal_classify ac



        INNER JOIN xml_template xt
        ON ac.entry_id = CAST(xt.template_id AS CHAR CHARACTER SET utf8mb4) COLLATE utf8mb4_unicode_ci and ac.entry_id = xt.template_id
        AND ac.entry_type = 'Vehicle Template'
        WHERE xt.deleted = 0

            AND xt.template_id = #{vehicleModel}






        INNER JOIN vehicle_info vi
        ON ac.entry_id = CAST(vi.vehicle_id AS CHAR CHARACTER SET utf8mb4) COLLATE utf8mb4_unicode_ci and ac.entry_id = vi.vehicle_id
        AND ac.entry_type = 'Vehicle Info'
        WHERE vi.deleted = 0

            AND vi.issue_date >= #{issueStartTime}


            AND vi.issue_date < #{issueEndTime}


            AND vi.factory_code = #{factoryCode}


            AND vi.vehicle_model = #{vehicleModel}


            AND vi.country like concat('%',#{country},'%')


            AND vi.upload_status = #{uploadResult}





        INNER JOIN xml_file xf
        ON ac.entry_id = CAST(xf.id AS CHAR CHARACTER SET utf8mb4) COLLATE utf8mb4_unicode_ci and ac.entry_id = xf.id
        AND ac.entry_type = 'XML File'
        WHERE xf.deleted = 0
        AND xf.is_latest = 1

            AND xf.issue_date >= #{issueStartTime}


            AND xf.issue_date < #{issueEndTime}


            AND xf.factory_code = #{factoryCode}


            AND xf.model_code = #{vehicleModel}


            AND xf.country like concat('%',#{country},'%')


            AND xf.upload_result = #{uploadResult}




    AND ac.create_time >= #{startTime}


    AND ac.create_time < #{endTime}

GROUP BY ac.rule_type
ORDER BY count DESC
